// CJS wrapper for ESM admin-auth module
// This allows CommonJS bundled lambdas (like samlslist/dist) to use this layer

let _module;

async function loadModule() {
  if (!_module) {
    _module = await import('./index.mjs');
  }
  return _module;
}

// Re-export all functions as async wrappers
module.exports.validateTenantAccess = async function(...args) {
  const mod = await loadModule();
  return mod.validateTenantAccess(...args);
};

module.exports.getTenantIdFromRequest = function(...args) {
  // This is synchronous in the ESM version, so we load module eagerly
  // For CJS consumers, we provide a sync fallback that reads headers directly
  const event = args[0];
  if (!event) return null;
  
  // Try X-Tenant-Id header first (primary method from frontend)
  const headers = event.headers || {};
  const tenantIdHeader = headers['x-tenant-id'] || headers['X-Tenant-Id'];
  if (tenantIdHeader) return tenantIdHeader;
  
  // Try query parameters
  if (event.queryStringParameters?.tenant_id) return event.queryStringParameters.tenant_id;
  
  // Try path parameters
  if (event.pathParameters?.tenant_id) return event.pathParameters.tenant_id;
  
  // Try request body
  try {
    const body = JSON.parse(event.body || '{}');
    if (body.tenant_id) return body.tenant_id;
  } catch (error) {
    // Invalid JSON body, continue
  }
  
  return null;
};

module.exports.createResponse = function(statusCode, body, tenantId) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Headers': 'Content-Type,Authorization,X-Api-Key,X-Tenant-Id,Content-Range,X-Requested-With',
      'Access-Control-Allow-Methods': 'OPTIONS,GET,POST,PUT,DELETE',
      'Access-Control-Expose-Headers': 'Content-Range',
    },
    body: JSON.stringify(body),
  };
};

