module.exports.isValidRole = function(...args) {
  // Sync function - inline implementation
  const role = args[0];
  if (!role) return false;
  return role === 'SA' || role.startsWith('SPA_') || role.startsWith('TA_');
};

module.exports.extractRolesFromEvent = function(event) {
  // Sync implementation matching admin-utils.mjs
  const jwtClaims = event?.requestContext?.authorizer?.jwt?.claims;
  if (!jwtClaims) return [];

  let groups = jwtClaims["cognito:groups"];
  if (!groups) return [];

  // Handle string format (parse if needed)
  if (typeof groups === "string") {
    groups = groups.match(/[^\[\]\s]+/g);
  }

  const validRoles = Array.isArray(groups)
    ? groups.filter(role => role === 'SA' || role.startsWith('SPA_') || role.startsWith('TA_'))
    : [];
  return module.exports.prioritizeRoles(validRoles);
};

module.exports.prioritizeRoles = function(roles) {
  if (!roles || roles.length === 0) return [];
  if (roles.includes("SA")) return ["SA"];
  const spaRole = roles.find(role => role.startsWith("SPA_"));
  if (spaRole) return [spaRole];
  const taRoles = roles.filter(role => role.startsWith("TA_"));
  return taRoles.length > 0 ? taRoles : [];
};

