module.exports.createAdminResponse = function(statusCode, data, error) {
  // Sync implementation matching admin-utils.mjs
  const headers = {
    "Access-Control-Allow-Headers": "Content-Type,Authorization,X-Api-Key,X-Requested-With",
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "OPTIONS,GET,POST,PUT,DELETE",
  };
  const body = error
    ? JSON.stringify({ type: error.type || "error", message: error.message })
    : JSON.stringify({ data });
  return { statusCode, headers, body };
};

// Structured logger for JSON CloudWatch Logs (2.2)
// CJS version matching logger.mjs API: createLogger(serviceName, defaultKeys)
const _LOG_LEVELS = { DEBUG: 0, INFO: 1, WARN: 2, ERROR: 3 };

module.exports.createLogger = function(serviceName, defaultKeys = {}) {
  const configuredLevel = (process.env.LOG_LEVEL || 'INFO').toUpperCase();
  const minLevel = _LOG_LEVELS[configuredLevel] ?? _LOG_LEVELS.INFO;
  let persistentKeys = { ...defaultKeys };

  function log(level, message, extra = {}) {
    if ((_LOG_LEVELS[level] ?? 0) < minLevel) return;
    const entry = {
      timestamp: new Date().toISOString(),
      level,
      service: serviceName,
      message,
      ...persistentKeys,
      ...extra,
    };
    Object.keys(entry).forEach(k => { if (entry[k] === undefined) delete entry[k]; });
    console.log(JSON.stringify(entry));
  }

  return {
    info: (message, extra) => log('INFO', message, extra),
    warn: (message, extra) => log('WARN', message, extra),
    error: (message, extra) => log('ERROR', message, extra),
    debug: (message, extra) => log('DEBUG', message, extra),
    appendKeys: (keys) => { persistentKeys = { ...persistentKeys, ...keys }; },
    resetKeys: () => { persistentKeys = { ...defaultKeys }; },
  };
};
